import time
import functools
import threading
from enum import Enum

class CircuitBreakerState(Enum):
    CLOSED = 1
    OPEN = 2
    HALF_OPEN = 3

class CircuitBreakerError(Exception):
    """Servis devresi açıkken çağrı yapıldığında fırlatılan özel istisna."""
    pass

class CircuitBreaker:
    def __init__(self, failure_threshold=5, recovery_timeout=60, half_open_success_threshold=3, expected_exception=Exception):
        self.failure_threshold = failure_threshold
        self.recovery_timeout = recovery_timeout
        self.half_open_success_threshold = half_open_success_threshold
        self.expected_exception = expected_exception

        self._state = CircuitBreakerState.CLOSED
        self._failure_count = 0
        self._success_count = 0
        self._open_transition_time = None

        self._lock = threading.Lock()

    def __call__(self, func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            with self._lock:
                if self._state == CircuitBreakerState.OPEN:
                    if time.monotonic() - self._open_transition_time > self.recovery_timeout:
                        self._state = CircuitBreakerState.HALF_OPEN
                        self._success_count = 0
                    else:
                        raise CircuitBreakerError("Circuit is OPEN")

            try:
                result = func(*args, **kwargs)
                with self._lock:
                    if self._state == CircuitBreakerState.HALF_OPEN:
                        self._success_count += 1
                        if self._success_count >= self.half_open_success_threshold:
                            self._state = CircuitBreakerState.CLOSED
                            self._failure_count = 0
                            self._success_count = 0
                            self._open_transition_time = None
                    elif self._state == CircuitBreakerState.CLOSED:
                        self._failure_count = 0
                return result
            except self.expected_exception as e:
                with self._lock:
                    if self._state == CircuitBreakerState.HALF_OPEN:
                        self._state = CircuitBreakerState.OPEN
                        self._open_transition_time = time.monotonic()
                        self._failure_count = 0
                        self._success_count = 0
                    elif self._state == CircuitBreakerState.CLOSED:
                        self._failure_count += 1
                        if self._failure_count >= self.failure_threshold:
                            self._state = CircuitBreakerState.OPEN
                            self._open_transition_time = time.monotonic()
                            self._success_count = 0
                raise e
        return wrapper
